import { describe, expect, it } from 'vitest';

import {
  admitPristine,
  CodecAncestryMaster,
  encoded,
  hasCutoff,
  hasSupport,
  pristine,
  totalEnergy,
  transcode,
  transcodeFlagged,
  zeroSpec,
  type Spectrum,
} from '../src/codec-ancestry';

describe('totalEnergy / support gate (mirrors totalEnergy / HasSupport)', () => {
  it('sums the per-band magnitudes', () => {
    expect(totalEnergy(pristine)).toBe(27);
    expect(totalEnergy(encoded)).toBe(22);
    expect(totalEnergy(transcode)).toBe(12);
    expect(totalEnergy(zeroSpec)).toBe(0);
  });

  it('an empty spectrum has zero energy', () => {
    expect(totalEnergy([])).toBe(0);
  });

  it('a spectrum with energy has support', () => {
    expect(hasSupport(pristine)).toBe(true);
    expect(hasSupport(encoded)).toBe(true);
    expect(hasSupport(transcode)).toBe(true);
  });

  it('an all-zero spectrum (and empty) has no support', () => {
    expect(hasSupport(zeroSpec)).toBe(false);
    expect(hasSupport([])).toBe(false);
    expect(hasSupport([0, 0, 0])).toBe(false);
  });
});

describe('hasCutoff (mirrors hasCutoffB / pristine_no_cutoff / encoded_has_cutoff)', () => {
  it('a full-band spectrum (nonzero top band) shows no cutoff', () => {
    expect(hasCutoff(pristine)).toBe(false);
  });

  it('an encoded spectrum with a zeroed high tail above energy shows a cutoff', () => {
    // energy 5,7,6,4 below, then the nonempty all-zero tail [0,0]
    expect(hasCutoff(encoded)).toBe(true);
  });

  it('a tighter transcode (larger zero tail) still shows a cutoff', () => {
    // energy 5,7 below, then the all-zero tail [0,0,0,0]
    expect(hasCutoff(transcode)).toBe(true);
  });

  it('an all-zero spectrum shows no cutoff (no energy was ever seen below)', () => {
    expect(hasCutoff(zeroSpec)).toBe(false);
    expect(hasCutoff([])).toBe(false);
    expect(hasCutoff([0, 0, 0])).toBe(false);
  });

  it('a leading-zero spectrum with energy then top band nonzero is not flagged', () => {
    // [0,0,5,7]: zeros are below the energy, not an all-zero tail above it
    expect(hasCutoff([0, 0, 5, 7])).toBe(false);
  });

  it('a single zeroed top band above energy is a (minimal) cutoff', () => {
    expect(hasCutoff([5, 7, 0])).toBe(true);
  });

  it('transcodeFlagged is exactly hasCutoff', () => {
    for (const s of [pristine, encoded, transcode, zeroSpec]) {
      expect(transcodeFlagged(s)).toBe(hasCutoff(s));
    }
  });
});

describe('promotion check: admitPristine', () => {
  it('admits a supported, cutoff-free spectrum as a pristine original', () => {
    // mirrors pristine_admitted
    const a = admitPristine(pristine);
    expect(a.outcome).toBe('claim_admitted');
    expect(a.limitation).toBe('none');
    expect(a.supported).toBe(true);
    expect(a.cutoff).toBe(false);
    expect(a.totalEnergy).toBe(27);
  });

  it('withholds an all-zero spectrum (no audio to certify)', () => {
    // mirrors zeroSpec_not_admitted
    const a = admitPristine(zeroSpec);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('no_audio');
    expect(a.supported).toBe(false);
    expect(a.totalEnergy).toBe(0);
  });

  it('withholds an encoded copy with a compression cutoff (transcode / re-upload)', () => {
    // mirrors encoded_not_admitted
    const a = admitPristine(encoded);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('compression_ancestry');
    expect(a.supported).toBe(true);
    expect(a.cutoff).toBe(true);
    expect(a.remediation).toContain('re-upload');
  });

  it('withholds a tighter transcode the same way (cutoff persists)', () => {
    const a = admitPristine(transcode);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('compression_ancestry');
    expect(a.cutoff).toBe(true);
  });

  it('the support gate fires before the cutoff gate (silence is no_audio)', () => {
    // an all-zero spectrum has no energy, so it is withheld for no_audio even
    // though it carries no cutoff either.
    const a = admitPristine(zeroSpec);
    expect(a.limitation).toBe('no_audio');
    expect(a.cutoff).toBe(false);
  });
});

describe('hard negative: same content, different ancestry', () => {
  it('pristine and encoded share their low bands but split on admission', () => {
    // mirrors same_content_different_ancestry / fixtures_share_low_bands
    expect(pristine.slice(0, 4)).toEqual(encoded.slice(0, 4));
    expect(admitPristine(pristine).outcome).toBe('claim_admitted');
    expect(admitPristine(encoded).outcome).not.toBe('claim_admitted');
  });

  it('the distinction is the silenced high tail, not the surviving content', () => {
    const sharedLow: Spectrum = pristine.slice(0, 4);
    expect(hasCutoff(sharedLow)).toBe(false); // the shared low content alone is clean
    expect(hasCutoff(encoded)).toBe(true); // the appended zero tail is what flags it
  });
});

describe('CodecAncestryMaster (mirrors codec_ancestry_master)', () => {
  it('every boundary witness holds', () => {
    expect(CodecAncestryMaster.pristineHasSupport).toBe(true);
    expect(CodecAncestryMaster.zeroSpecNoSupport).toBe(true);
    expect(CodecAncestryMaster.pristineNoCutoff).toBe(true);
    expect(CodecAncestryMaster.encodedHasCutoff).toBe(true);
    expect(CodecAncestryMaster.transcodeHasCutoff).toBe(true);
    expect(CodecAncestryMaster.pristineAdmitted).toBe(true);
    expect(CodecAncestryMaster.encodedNotAdmitted).toBe(true);
    expect(CodecAncestryMaster.zeroSpecNotAdmitted).toBe(true);
    expect(CodecAncestryMaster.encodedFlagged).toBe(true);
    expect(CodecAncestryMaster.transcodeFlagged).toBe(true);
    expect(CodecAncestryMaster.pristineNotFlagged).toBe(true);
    expect(CodecAncestryMaster.fixturesShareLowBands).toBe(true);
  });
});
